    $.validator.methods = $.validator.methods || {};
    $.validator.defaults = $.validator.defaults || {};

    $.validator.addMethod = $.validator.addMethod || function (name, method) {
        $.validator.methods[name] = method;
    };

    $.validator.setDefaults = $.validator.setDefaults || function (options) {
        $.validator.defaults = $.extend(true, $.validator.defaults, options || {});
    };

